/* ── Reactions ── */
.reaction-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 1px 8px;
    font-size: 0.78rem;
    cursor: pointer;
    transition: background 0.1s;
}

.reaction-badge:hover {
    background: #e0e0ff;
    border-color: #aac;
}

/* ── Thread link ── */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 2px 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

/* ── Message hover actions ── */
.message-actions {
    position: absolute;
    top: -4px;
    right: 8px;
    display: flex;
    gap: 4px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px 4px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    font-size: 0.78rem;
    cursor: pointer;
    padding: 3px 6px;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f0;
}

/* ── Emoji picker ── */
.emoji-picker {
    position: absolute;
    top: -4px;
    right: 160px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    padding: 4px 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    z-index: 6;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 2px 4px;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-option:hover {
    background: #f0f0f0;
}

/* ── Message input area ── */
.message-input-area {
    display: flex;
    gap: 8px;
    padding: 10px 20px 14px;
    border-top: 1px solid #e1e1e1;
    flex-shrink: 0;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 8px 10px;
    font-size: 0.88rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #1264a3;
}

.send-btn {
    align-self: flex-end;
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 6px;
    padding: 8px 18px;
    font-size: 0.88rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.12s;
}

.send-btn:hover:not(:disabled) {
    background: #005e44;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ── Thread panel ── */
.chat-thread-panel {
    width: 25%;
    min-width: 260px;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-left: 1px solid #e1e1e1;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e1e1e1;
    flex-shrink: 0;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-thread-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 2px 6px;
    border-radius: 4px;
}

.close-thread-btn:hover {
    background: #f0f0f0;
    color: #333;
}

.thread-root-quote {
    padding: 10px 16px;
    background: #f8f8f8;
    border-bottom: 1px solid #e1e1e1;
    flex-shrink: 0;
}

.thread-root-quote .message-author {
    font-size: 0.85rem;
}

.thread-root-quote p {
    margin: 4px 0 0;
    font-size: 0.85rem;
    color: #555;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 10px 16px;
}

.thread-replies .message-bubble {
    padding: 6px 0;
}
"}

