namespace sv_bbd06faab355427591e2d42ce6482fe7.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_bbd06faab355427591e2d42ce6482fe7.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="chat-sidebar" role="navigation" aria-label="Channel list">
        <div class="sidebar-header">
            <h2>Channels</h2>
        </div>
        <ul class="channel-list">
            @foreach (var ch in channels)
            {
                <li class="channel-item @(ch.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(ch.Id)"
                    role="button"
                    tabindex="0">
                    <div class="channel-name"># @ch.Name</div>
                    <div class="channel-desc">@Truncate(ch.Description, 48)</div>
                    @if (ch.UnreadCount > 0)
                    {
                        <span class="unread-badge">@ch.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="chat-main @(threadOpen ? "" : "chat-main-wide")">
        @if (activeChannel is not null)
        {
            <header class="main-header">
                <h3># @activeChannel.Name</h3>
                <span class="main-header-desc">@activeChannel.Description</span>
            </header>

            <div class="message-list" @ref="messageListRef" @onscroll="OnMessageListScroll">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-row" @onmouseenter="() => hoveredMessageId = msg.Id"
                         @onmouseleave="() => { if (hoveredMessageId == msg.Id) hoveredMessageId = null; }">
                        <div class="message-bubble">
                            <div class="message-meta">
                                <span class="message-author">@msg.Author</span>
                                <span class="message-time">@RelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="message-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => AddReactionAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var summary = threadSummaries.GetValueOrDefault(msg.Id); }
                            @if (summary is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                </button>
                            }
                        </div>

                        @if (hoveredMessageId == msg.Id)
                        {
                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread"
                                        @onclick="() => OpenThreadAsync(msg.Id)">💬 Reply</button>
                                <button class="action-btn" title="Add reaction"
                                        @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                            </div>
                            @if (emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in commonEmojis)
                                    {
                                        <button class="emoji-option" @onclick="() => AddReactionAsync(msg.Id, emoji)">@emoji</button>
                                    }
                                </div>
                            }
                        }
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-textarea" rows="2" placeholder="Type a message…"
                          @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="OnMainKeyDown"></textarea>
                <button class="send-btn" @onclick="SendMainMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">Send</button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="chat-thread-panel">
            <header class="thread-header">
                <h4>Thread</h4>
                <button class="close-thread-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </header>

            <div class="thread-root-quote">
                <span class="message-author">@threadRootMessage.Author</span>
                <p>@threadRootMessage.Content</p>
            </div>

            <div class="thread-replies">
                @foreach (var reply in threadReplies)
                {
                    <div class="message-bubble">
                        <div class="message-meta">
                            <span class="message-author">@reply.Author</span>
                            <span class="message-time">@RelativeTime(reply.SentAt)</span>
                        </div>
                        <div class="message-content">@reply.Content</div>
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-textarea" rows="2" placeholder="Reply in thread…"
                          @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="OnThreadKeyDown"></textarea>
                <button class="send-btn" @onclick="SendThreadReplyAsync" disabled="@string.IsNullOrWhiteSpace(threadReplyText)">Reply</button>
            </div>
        </aside>
    }
</div>

@code {
    // ── State ──
    private List<Channel> channels = new();
    private int? activeChannelId;
    private Channel? activeChannel;

    private List<Message> messages = new();
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private int currentSkip;
    private const int PageSize = 30;
    private bool isLoadingMore;
    private bool allMessagesLoaded;

    private string newMessageText = string.Empty;
    private int? hoveredMessageId;
    private int? emojiPickerMessageId;

    // Thread state
    private bool threadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = new();
    private string threadReplyText = string.Empty;

    private ElementReference messageListRef;

    private static readonly string[] commonEmojis = { "👍", "❤️", "😂", "🎉", "🚀", "👀" };

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannelAsync(channels[0].Id);
        }
    }

    // ── Channel selection ──

    private async Task SelectChannelAsync(int channelId)
    {
        if (activeChannelId == channelId) return;

        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages.Clear();
        threadSummaries.Clear();
        currentSkip = 0;
        allMessagesLoaded = false;
        CloseThread();

        await LoadMessagesAsync();
        _ = ChatService.MarkChannelReadAsync(channelId);

        // Refresh channels to update unread badge
        channels = await ChatService.GetChannelsAsync();

        await ScrollToBottom();
    }

    // ── Message loading ──

    private async Task LoadMessagesAsync()
    {
        var batch = await ChatService.GetMessagesAsync(activeChannelId!.Value, currentSkip, PageSize);
        if (batch.Count < PageSize)
        {
            allMessagesLoaded = true;
        }

        // Prepend older messages
        messages.InsertRange(0, batch);
        currentSkip += batch.Count;

        // Build thread summaries from messages that are reply targets
        await RebuildThreadSummaries();
    }

    private async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || allMessagesLoaded) return;
        isLoadingMore = true;
        StateHasChanged();

        await LoadMessagesAsync();

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task RebuildThreadSummaries()
    {
        // Identify messages that are root of threads (have replies pointing to them)
        var rootIds = messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct()
            .ToHashSet();

        // Also include existing roots from messages with no inline replies yet
        foreach (var rootId in rootIds)
        {
            if (!threadSummaries.ContainsKey(rootId))
            {
                try
                {
                    var thread = await ChatService.GetThreadAsync(rootId);
                    if (thread.Count > 0)
                    {
                        threadSummaries[rootId] = new ThreadSummary(
                            rootId,
                            thread.Count,
                            thread.Max(t => t.SentAt));
                    }
                }
                catch
                {
                    // Thread may not exist yet
                }
            }
        }
    }

    // ── Sending messages ──

    private async Task SendMainMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId.Value, newMessageText.Trim(), null);
        messages.Add(sent);
        newMessageText = string.Empty;

        await ScrollToBottom();
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null || activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, threadReplyText.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);
        threadReplyText = string.Empty;

        // Update thread summary
        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            threadReplies.Count,
            reply.SentAt);
    }

    // ── Keyboard shortcuts (Enter to send) ──

    private async Task OnMainKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMainMessageAsync();
        }
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Thread panel ──

    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadReplyText = string.Empty;
        threadOpen = true;

        // Update summary
        if (threadReplies.Count > 0)
        {
            threadSummaries[rootMessageId] = new ThreadSummary(
                rootMessageId,
                threadReplies.Count,
                threadReplies.Max(r => r.SentAt));
        }
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
        threadReplyText = string.Empty;
    }

    // ── Reactions ──

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Optimistically update local state
        var msg = messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
            }
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    // ── Scroll handling ──

    private async Task OnMessageListScroll()
    {
        // Use JS interop to detect scroll position
        var scrollTop = await JS.InvokeAsync<double>("eval", $"document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            await LoadOlderMessagesAsync();
        }
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        try
        {
            await JS.InvokeVoidAsync("eval", "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
        }
        catch { }
    }

    // ── Helpers ──

    private static string Truncate(string text, int maxLen) =>
        text.Length <= maxLen ? text : text[..(maxLen - 1)] + "…";

    private static string RelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

